import { test, expect } from '@playwright/test'
import { searchWith, waitForResults } from './helpers'

// ── Critical ────────────────────────────────────────────────────────────────

test.describe('Authentication & Preferences — Critical', () => {
  test('unauthenticated state shows Sign In button in header @critical @auth', async ({
    page,
  }) => {
    await page.goto('/')

    // When no user is authenticated, the header should display the Sign In button
    const signInButton = page.getByRole('button', { name: 'Sign In' })
    await expect(signInButton).toBeVisible({ timeout: 10_000 })
  })
})

// ── Standard ────────────────────────────────────────────────────────────────

test.describe('Authentication & Preferences — Standard', () => {
  test('sign-in dropdown shows Continue with Google option @standard @auth', async ({
    page,
  }) => {
    await page.goto('/')

    // Click the Sign In button to open the menu dropdown
    const signInButton = page.getByRole('button', { name: 'Sign In' })
    await expect(signInButton).toBeVisible({ timeout: 10_000 })
    await signInButton.click()

    // The dropdown menu should show "Continue with Google"
    const googleOption = page.getByRole('menuitem', { name: 'Continue with Google' })
    await expect(googleOption).toBeVisible({ timeout: 5_000 })
  })

  // Signed-in state test: skipped because mocking Supabase auth state requires
  // intercepting the Supabase client initialization and injecting a fake session
  // into the Zustand auth store. This is fragile and tightly coupled to Supabase
  // internals. A proper implementation would need either:
  //   1. A test Supabase project with a service-role key for programmatic sign-in
  //   2. A custom auth bypass endpoint in the dev server
  //   3. Playwright route interception for all Supabase auth endpoints
  // For now, the unauthenticated tests above provide coverage of the auth UI.
  test.skip('signed-in state shows user menu with name and email @standard @auth', async ({
    page,
  }) => {
    // TODO: Implement when mock auth setup is available.
    // Expected flow:
    //   1. Mock Supabase auth response via page.route() or inject session into localStorage
    //   2. Navigate to /
    //   3. Verify avatar/initials element is visible (UserMenu renders instead of SignInMenu)
    //   4. Click the avatar to open the user menu dropdown
    //   5. Verify user's full name and email are displayed in the menu
    //   6. Verify "Sign out" menu item is present
    await page.goto('/')
  })
})

// ── Comprehensive ───────────────────────────────────────────────────────────

test.describe('Authentication & Preferences — Comprehensive', () => {
  test('preferences round-trip: set location via ZIP then reload preserves location in URL @comprehensive @auth', async ({
    page,
  }) => {
    // Navigate to the search page
    await searchWith(page, {})
    await waitForResults(page)

    // Find the ZIP code input in the sidebar LocationInput component
    const zipInput = page.getByLabel('ZIP code')
    await expect(zipInput).toBeVisible({ timeout: 10_000 })

    // Enter a ZIP code and submit
    await zipInput.fill('02134')
    await page.getByRole('button', { name: 'Go' }).click()

    // Wait for the ZIP code to resolve and the URL to update with location params
    await expect(page).toHaveURL(/userLat=/, { timeout: 10_000 })
    await expect(page).toHaveURL(/userLng=/)

    // Capture the current URL with location params
    const urlAfterSet = page.url()
    const parsedUrl = new URL(urlAfterSet)
    const userLat = parsedUrl.searchParams.get('userLat')
    const userLng = parsedUrl.searchParams.get('userLng')
    expect(userLat).toBeTruthy()
    expect(userLng).toBeTruthy()

    // The location display should show "City, State" text (e.g., "Allston, MA")
    // LocationInput renders a MapPin icon + display name when a value is set
    const clearLocationButton = page.getByRole('button', { name: 'Clear location' })
    await expect(clearLocationButton).toBeVisible({ timeout: 5_000 })

    // Reload the page using the same URL (which preserves the location params)
    await page.reload()
    await waitForResults(page)

    // After reload, the URL should still have the same location params
    await expect(page).toHaveURL(/userLat=/)
    await expect(page).toHaveURL(/userLng=/)

    // The location display should still be visible (not the ZIP input form)
    await expect(clearLocationButton).toBeVisible({ timeout: 10_000 })

    // Verify the location params match what was set before reload
    const urlAfterReload = page.url()
    const parsedReload = new URL(urlAfterReload)
    expect(parsedReload.searchParams.get('userLat')).toBe(userLat)
    expect(parsedReload.searchParams.get('userLng')).toBe(userLng)
  })
})

